// La estructura del DOM refleja el HTML
// Dado este HTML:
// <body>
//   <h1 id="titulo">Hola</h1>
//   <p class="intro">Bienvenido</p>
// </body>

console.log(document.body.children.length); // 2 (h1 y p)
console.log(document.body.children[0].tagName); // 'H1'

// Relaciones entre nodos
const body = document.body;

console.log(body.parentNode.tagName);   // 'HTML' (padre)
console.log(body.firstElementChild);    // primer hijo
console.log(body.lastElementChild);     // último hijo

